const allDivs=document.querySelectorAll(".event-card-wrap div"),mainEvent=document.getElementById("main-event");let cards;cards=mainEvent?Array.from(allDivs).filter((el=>!mainEvent.contains(el))):Array.from(allDivs);const extras=document.querySelectorAll("#main-event img, #main-event h4"),finalTargets=[...cards,...extras];finalTargets.forEach((function(element){element.addEventListener("click",(function(e){if(!e.target.closest("a")){let parent=element;for(;parent&&!parent.querySelector("a");)parent=parent.parentElement;const link=parent?.querySelector("a");link&&link.click()}}))}));